    /**
     * @ignore
     * @method
     * @name hyperliquid#slugifyUpper
     * @description converts a name into an upper-case slug of alphanumeric parts joined by hyphens
     * @param {string} name the raw name to slugify
     * @returns {string} the upper-case slug
     */
