    /**
     * @ignore
     * @method
     * @name hyperliquid#calculatePricePrecision
     * @description calculates an appropriate price precision tick size given midPx and szDecimals
     * @param {float} midPx the mid price
     * @param {int} szDecimals the number of size decimals
     * @returns {float} the price tick size
     */
    public virtual object calculatePricePrecision(object midPx, object szDecimals)
    {
        if (isTrue(isLessThanOrEqual(midPx, 0)))
        {
            return 0.0001;
        }
        object midStr = this.numberToString(midPx);
        object parts = ((string)midStr).Split(new [] {((string)".")}, StringSplitOptions.None).ToList<object>();
        object intPart = getValue(parts, 0);
        object significantDigits = mathMax(5, ((string)intPart).Length);
        object maxDecimals = subtract(8, szDecimals);
        object pricePrecisionDecimals = mathMax(1, mathMin(maxDecimals, subtract(significantDigits, ((string)intPart).Length)));
        object zeros = "";
        object zeroCount = subtract(pricePrecisionDecimals, 1);
        for (object zi = 0; isLessThan(zi, zeroCount); postFixIncrement(ref zi))
        {
            zeros = add(zeros, "0");
        }
        return this.parseToNumeric(add(add("0.", zeros), "1"));
    }

    /**
     * @method
     * @name hyperliquid#fetchTicker
     * @description fetches a ticker for a single outcome market using the L2 order book snapshot
     * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#l2-book-snapshot
     * @param {string} outcome unified outcome (e.g. 'BTC-ABOVE-78213-20260503:YES')
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
     */
    public async override Task<object> fetchTicker(object outcome, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        await this.loadOutcome(outcome);
        object outcomeObj = this.outcome(outcome);
        object info = this.safeDict(outcomeObj, "info", new Dictionary<string, object>() {});
        object coin = this.safeString(info, "coinName");
        object request = new Dictionary<string, object>() {
            { "type", "l2Book" },
            { "coin", coin },
        };
        object response = await this.publicPostInfo(this.extend(request, parameters));
        //
        //     {
        //         "coin": "#10",
        //         "levels": [
        //             [ { "n": "2", "px": "0.44", "sz": "500" } ],   // bids [0]
        //             [ { "n": "2", "px": "0.46", "sz": "400" } ]    // asks [1]
        //         ],
        //         "time": 1704290104840
        //     }
        //
        // l2Book returns null for coins without an order book; coerce to an empty dict
        object tickerData = this.safeDict(new Dictionary<string, object>() {
            { "book", response },
        }, "book", new Dictionary<string, object>() {});
        return this.parsePredictionTicker(tickerData, outcomeObj);
    }

    /**
     * @method
     * @name hyperliquid#fetchTickers
     * @description fetches all outcome market tickers using allMids then optionally enriches with l2Book
     * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#retrieve-all-mids-for-all-actively-traded-coins
     * @param {string[]} [outcomes] filter by outcome ids or outcomes
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [ticker structures](https://docs.ccxt.com/#/?id=ticker-structure)
     */
    public async virtual Task<object> fetchTickers(object outcomes = null, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        object requestedOutcomeSymbols = new Dictionary<string, object>() {};
        if (isTrue(!isEqual(outcomes, null)))
        {
            for (object i = 0; isLessThan(i, getArrayLength(outcomes)); postFixIncrement(ref i))
            {
                object requested = getValue(outcomes, i);
                object requestedOutcomeObj = await this.loadOutcome(requested);
                object requestedOutcome = this.safeString(requestedOutcomeObj, "outcome", requested);
                ((IDictionary<string,object>)requestedOutcomeSymbols)[(string)requestedOutcome] = true;
            }
        } else
        {
            // no filter — warm the whole outcome set so identities resolve from the cache
            await this.loadOutcomes();
        }
        object response = await this.publicPostInfo(this.extend(new Dictionary<string, object>() {
            { "type", "allMids" },
        }, parameters));
        //
        // { "mids": { "#10": "0.45", "#11": "0.55", ... } }
        //
        object mids = this.safeDict(response, "mids", response);
        object tickers = new Dictionary<string, object>() {};
        object outcomesMap = ((bool) isTrue((!isEqual(this.outcomes, null)))) ? this.outcomes : new Dictionary<string, object>() {};
        object outcomeHandles = new List<object>(((IDictionary<string,object>)outcomesMap).Keys);
        for (object i = 0; isLessThan(i, getArrayLength(outcomeHandles)); postFixIncrement(ref i))
        {
            object outcomeHandle = getValue(outcomeHandles, i);
            if (isTrue(isTrue(!isEqual(outcomes, null)) && !isTrue((inOp(requestedOutcomeSymbols, outcomeHandle)))))
            {
                continue;
            }
            object outcomeObj = this.safeDict(outcomesMap, outcomeHandle, new Dictionary<string, object>() {});
            object info = this.safeDict(outcomeObj, "info", new Dictionary<string, object>() {});
            object coin = this.safeString(info, "coinName");
            object mid = this.safeNumber(mids, coin);
            if (isTrue(isEqual(mid, null)))
            {
                continue;
            }
            // Build minimal ticker from mid price
            object ticker = this.parsePredictionTicker(new Dictionary<string, object>() {
                { "levels", new List<object>() {new List<object>() {}, new List<object>() {}} },
                { "mid", mid },
                { "time", this.milliseconds() },
            }, ((object)outcomeObj));
            ((IDictionary<string,object>)tickers)[(string)outcomeHandle] = ticker;
        }
        return tickers;
    }

    /**
     * @ignore
     * @method
     * @name hyperliquid#parsePredictionTicker
     * @description parses a raw l2Book response (or a synthetic mid dict) into a unified ticker object
     * @param {object} raw l2Book response or { mid, time } object
     * @param {object} [market] the market the ticker belongs to
     * @returns {object} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
     */
    public override object parsePredictionTicker(object raw, object market = null)
    {
        //
        //     {
        //         "coin": "#10",
        //         "levels": [
        //             [ { "n": "2", "px": "0.44", "sz": "500" } ],   // bids [0]
        //             [ { "n": "2", "px": "0.46", "sz": "400" } ]    // asks [1]
        //         ],
        //         "time": 1704290104840
        //     }
        //
        object now = this.milliseconds();
        object timestamp = this.safeInteger(raw, "time", now);
        // the 2nd arg carries the outcome object (callers pass the resolved outcome)
        object mkt = this.safeOutcome(null, market);
        object outcome = this.safeString(mkt, "outcome");
        object levels = this.safeList(raw, "levels", new List<object>() {});
        object rawBids = this.safeList(levels, 0, new List<object>() {});
        object rawAsks = this.safeList(levels, 1, new List<object>() {});
        object topBid = this.safeDict(rawBids, 0);
        object topAsk = this.safeDict(rawAsks, 0);
        object bid = ((bool) isTrue((!isEqual(topBid, null)))) ? this.safeNumber(topBid, "px") : null;
        object ask = ((bool) isTrue((!isEqual(topAsk, null)))) ? this.safeNumber(topAsk, "px") : null;
        object bidVolume = ((bool) isTrue((!isEqual(topBid, null)))) ? this.safeNumber(topBid, "sz") : null;
        object askVolume = ((bool) isTrue((!isEqual(topAsk, null)))) ? this.safeNumber(topAsk, "sz") : null;
        // Use synthetic mid if no l2Book
        object mid = this.safeNumber(raw, "mid");
        if (isTrue(isTrue(isTrue(isEqual(mid, null)) && isTrue(!isEqual(bid, null))) && isTrue(!isEqual(ask, null))))
        {
            mid = divide(this.sum(bid, ask), 2);
        }
        // day volume lives on the parent market's ctx; resolve it from the outcome's parent market
        object parentSymbol = this.safeString(mkt, "market");
        object parentMarket = ((bool) isTrue((!isEqual(parentSymbol, null)))) ? this.safeMarket(parentSymbol) : null;
        object ctx = ((bool) isTrue((!isEqual(parentMarket, null)))) ? this.safeDict(this.safeDict(((object)parentMarket), "info", new Dictionary<string, object>() {}), "ctx", new Dictionary<string, object>() {}) : new Dictionary<string, object>() {};
        object dayVolume = this.safeNumber(ctx, "dayNtlVlm");
        return this.safePredictionTicker(new Dictionary<string, object>() {
            { "outcome", outcome },
            { "outcomeId", this.safeString2(mkt, "outcomeId", "id") },
            { "label", this.safeString(mkt, "label") },
            { "market", this.safeString(mkt, "market") },
            { "timestamp", timestamp },
            { "datetime", this.iso8601(timestamp) },
            { "high", null },
            { "low", null },
            { "bid", bid },
            { "bidVolume", bidVolume },
            { "ask", ask },
            { "askVolume", askVolume },
            { "vwap", null },
            { "open", null },
            { "close", mid },
            { "last", mid },
            { "previousClose", null },
            { "change", null },
            { "percentage", null },
            { "average", mid },
            { "baseVolume", null },
            { "quoteVolume", dayVolume },
            { "info", raw },
        }, market);
    }

    /**
     * @method
     * @name hyperliquid#fetchOrderBook
     * @description fetches the L2 order book for an outcome market
     * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#l2-book-snapshot
     * @param {string} outcome unified outcome
     * @param {int} [limit] max depth levels (not used by hyperliquid but accepted)
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order book structure](https://docs.ccxt.com/#/?id=order-book-structure)
     */
    public async override Task<object> fetchOrderBook(object outcome, object limit = null, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        await this.loadOutcome(outcome);
        object outcomeObj = this.outcome(outcome);
        object info = this.safeDict(outcomeObj, "info", new Dictionary<string, object>() {});
        object request = new Dictionary<string, object>() {
            { "type", "l2Book" },
            { "coin", this.safeString(info, "coinName") },
        };
        object response = await this.publicPostInfo(this.extend(request, parameters));
        //
        //     {
        //         "coin": "#10",
        //         "levels": [
        //             [ { "n": "5", "px": "0.44", "sz": "500" }, ... ],   // bids [0]
        //             [ { "n": "5", "px": "0.46", "sz": "400" }, ... ]    // asks [1]
        //         ],
        //         "time": 1704290104840
        //     }
        //
        object timestamp = this.safeInteger(response, "time");
        object levels = this.safeList(response, "levels", new List<object>() {});
        object rawBids = this.safeList(levels, 0, new List<object>() {});
        object rawAsks = this.safeList(levels, 1, new List<object>() {});
        object bids = new List<object>() {};
        object asks = new List<object>() {};
        for (object i = 0; isLessThan(i, getArrayLength(rawBids)); postFixIncrement(ref i))
        {
            object entry = getValue(rawBids, i);
            ((IList<object>)bids).Add(new List<object> {this.safeNumber(entry, "px"), this.safeNumber(entry, "sz")});
        }
        for (object i = 0; isLessThan(i, getArrayLength(rawAsks)); postFixIncrement(ref i))
        {
            object entry = getValue(rawAsks, i);
            ((IList<object>)asks).Add(new List<object> {this.safeNumber(entry, "px"), this.safeNumber(entry, "sz")});
        }
        object orderbook = this.parseOrderBook(new Dictionary<string, object>() {
            { "bids", bids },
            { "asks", asks },
        }, this.safeString(outcomeObj, "outcome", outcome), timestamp);
        return this.safePredictionOrderBook(orderbook, outcomeObj);
    }

    /**
     * @method
     * @name hyperliquid#fetchOHLCV
     * @description fetches candlestick OHLCV data for an outcome market
     * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#candle-snapshot
     * @param {string} outcome unified outcome
     * @param {string} timeframe '1m', '5m', '15m', '1h', '4h', '1d', etc.
     * @param {int} [since] timestamp in ms of earliest candle
     * @param {int} [limit] max number of candles
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] end timestamp in ms
     * @returns {int[][]} a list of candles ordered as timestamp, open, high, low, close, volume
     */
    public async override Task<object> fetchOHLCV(object outcome, object timeframe = null, object since = null, object limit = null, object parameters = null)
    {
        timeframe ??= "1m";
        parameters ??= new Dictionary<string, object>();
        await this.loadOutcome(outcome);
        object outcomeObj = this.outcome(outcome);
        // markets are keyed by the parent market outcome, not the outcome handle ("MARKET:LABEL")
        object market = this.market(this.safeString(outcomeObj, "market"));
        object info = this.safeDict(outcomeObj, "info", new Dictionary<string, object>() {});
        object until = this.safeInteger(parameters, "until", this.milliseconds());
        object startTime = since;
        if (isTrue(isEqual(since, null)))
        {
            object tf = this.parseTimeframe(timeframe);
            object candleCount = ((bool) isTrue((!isEqual(limit, null)))) ? limit : 100;
            object startOffset = multiply(multiply(tf, candleCount), -1000);
            startTime = this.sum(until, startOffset);
            if (isTrue(isLessThan(startTime, 0)))
            {
                startTime = 0;
            }
        }
        object request = new Dictionary<string, object>() {
            { "type", "candleSnapshot" },
            { "req", new Dictionary<string, object>() {
                { "coin", this.safeString(info, "coinName") },
                { "interval", this.safeString(this.timeframes, timeframe, timeframe) },
                { "startTime", startTime },
                { "endTime", until },
            } },
        };
        parameters = this.omit(parameters, "until");
        object response = await this.publicPostInfo(this.extend(request, parameters));
        //
        //     [
        //         {
        //             "T": 1704287699999,   // close time
        //             "c": "0.45",
        //             "h": "0.47",
        //             "i": "1m",
        //             "l": "0.43",
        //             "n": 46,              // number of trades
        //             "o": "0.44",
        //             "s": "#10",
        //             "t": 1704286800000,   // open time
        //             "v": "1234.5"
        //         }
        //     ]
        //
        return this.parseOHLCVs(response, market, timeframe, since, limit);
    }

    /**
     * @ignore
     * @method
     * @name hyperliquid#parseOHLCV
     * @description parses a single hyperliquid candle object into a CCXT OHLCV tuple
     * @param {object} ohlcv the raw candle object
     * @param {object} [market] the market the candle belongs to
     * @returns {int[]} a candle ordered as timestamp, open, high, low, close, volume
     */
    public override object parseOHLCV(object ohlcv, object market = null)
    {
        //
        //     {
        //         "T": 1704287699999,   // close time
        //         "c": "0.45",
        //         "h": "0.47",
        //         "i": "1m",
        //         "l": "0.43",
        //         "n": 46,              // number of trades
        //         "o": "0.44",
        //         "s": "#10",
        //         "t": 1704286800000,   // open time
        //         "v": "1234.5"
        //     }
        //
        return new List<object> {this.safeInteger(ohlcv, "t"), this.safeNumber(ohlcv, "o"), this.safeNumber(ohlcv, "h"), this.safeNumber(ohlcv, "l"), this.safeNumber(ohlcv, "c"), this.safeNumber(ohlcv, "v")};
    }

    /**
     * @method
     * @name hyperliquid#fetchBalance
     * @description Fetches spot balance (outcomes use spot-like balance).
     * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint/spot#retrieve-a-users-token-balances
     * @param {object} [params] extra parameters
     * @param {string} [params.user] wallet address (defaults to this.walletAddress)
     * @returns {Balances} balance structure
     */
    public async override Task<object> fetchBalance(object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        object userAddress = null;
        var userAddressparametersVariable = this.handlePublicAddress("fetchBalance", parameters);
        userAddress = ((IList<object>)userAddressparametersVariable)[0];
        parameters = ((IList<object>)userAddressparametersVariable)[1];
        object request = new Dictionary<string, object>() {
            { "type", "spotClearinghouseState" },
            { "user", userAddress },
        };
        object response = await this.publicPostInfo(this.extend(request, parameters));
        //
        //     {
        //         "balances": [
        //             { "coin": "USDC",  "hold": "0.0", "total": "100.0" },
        //             { "coin": "+10",   "hold": "0.0", "total": "50.0" }, // outcome token
        //             { "coin": "+11",   "hold": "0.0", "total": "25.0" }
        //         ]
        //     }
        //
        object result = new Dictionary<string, object>() {
            { "info", response },
        };
        object balances = this.safeList(response, "balances", new List<object>() {});
        for (object i = 0; isLessThan(i, getArrayLength(balances)); postFixIncrement(ref i))
        {
            object balance = getValue(balances, i);
            object coin = this.safeString(balance, "coin");
            object total = this.safeString(balance, "total");
            object used = this.safeString(balance, "hold");
            object account = this.account();
            ((IDictionary<string,object>)account)["total"] = total;
            ((IDictionary<string,object>)account)["used"] = used;
            ((IDictionary<string,object>)result)[(string)coin] = account;
        }
        return this.safeBalance(result);
    }

    /**
     * @method
     * @name hyperliquid#fetchPositions
     * @description fetches the user's outcome positions; outcome positions are spot token balances under the "+<encoding>" coin form (size and entry notional), the value/entry/mark price/pnl are computed from the current mid prices
     * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint/spot#retrieve-a-users-token-balances
     * @param {string[]} [outcomes] filter by outcome ids or outcomes
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.user] wallet address
     * @returns {object[]} a list of [position structures](https://docs.ccxt.com/#/?id=position-structure)
     */
    public async virtual Task<object> fetchPositions(object outcomes = null, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        object requestedOutcomeSymbols = new Dictionary<string, object>() {};
        if (isTrue(!isEqual(outcomes, null)))
        {
            for (object i = 0; isLessThan(i, getArrayLength(outcomes)); postFixIncrement(ref i))
            {
                object requested = getValue(outcomes, i);
                object requestedOutcomeObj = await this.loadOutcome(requested);
                object requestedOutcome = this.safeString(requestedOutcomeObj, "outcome", requested);
                ((IDictionary<string,object>)requestedOutcomeSymbols)[(string)requestedOutcome] = true;
            }
        } else
        {
            // no filter — warm the whole outcome set so identities resolve from the cache
            await this.loadOutcomes();
        }
        object userAddress = null;
        var userAddressparametersVariable = this.handlePublicAddress("fetchPositions", parameters);
        userAddress = ((IList<object>)userAddressparametersVariable)[0];
        parameters = ((IList<object>)userAddressparametersVariable)[1];
        object request = new Dictionary<string, object>() {
            { "type", "spotClearinghouseState" },
            { "user", userAddress },
        };
        // outcome positions are spot token balances under the "+<encoding>" coin form; they carry
        // the size (total) and entry notional (entryNtl). hyperliquid does not return the position
        // value / entry price / pnl, so they are computed from the current mid prices
        object promises = new List<object> {this.publicPostInfo(this.extend(request, parameters)), this.publicPostInfo(new Dictionary<string, object>() {
    { "type", "allMids" },
})};
        object results = await promiseAll(promises);
        object response = getValue(results, 0);
        object midsResponse = getValue(results, 1);
        object balances = this.safeList(response, "balances", new List<object>() {});
        object mids = this.safeDict(midsResponse, "mids", midsResponse);
        object positions = new List<object>() {};
        for (object i = 0; isLessThan(i, getArrayLength(balances)); postFixIncrement(ref i))
        {
            object balance = this.safeDict(balances, i, new Dictionary<string, object>() {});
            object coin = this.safeString(balance, "coin", "");
            // outcome tokens use the "+<encoding>" balance form; skip regular spot tokens (USDC, ...)
            if (isTrue(!isEqual(getIndexOf(coin, "+"), 0)))
            {
                continue;
            }
            object totalStr = this.safeString(balance, "total");
            if (isTrue(isTrue((isEqual(totalStr, null))) || isTrue(Precise.stringEq(totalStr, "0"))))
            {
                continue;
            }
            // the trade/orderbook form ("#<encoding>") resolves the outcome and the mid price
            object tradeCoin = add("#", slice(coin, 1, null));
            object outcomeObj = this.safeOutcome(tradeCoin);
            if (isTrue(!isEqual(outcomes, null)))
            {
                object outcomeHandle = this.safeString(outcomeObj, "outcome");
                if (isTrue(isTrue(isEqual(outcomeHandle, null)) || !isTrue((inOp(requestedOutcomeSymbols, outcomeHandle)))))
                {
                    continue;
                }
            }
            object enriched = this.extend(balance, new Dictionary<string, object>() {
                { "markPx", this.safeString(mids, tradeCoin) },
            });
            ((IList<object>)positions).Add(this.parsePredictionPosition(enriched, outcomeObj));
        }
        return positions;
    }

    /**
     * @ignore
     * @method
     * @name hyperliquid#parsePredictionPosition
     * @description parses a spot balance entry for an outcome token into a unified position object
     * @param {object} position the raw balance entry
     * @param {object} [market] the outcome object the position belongs to
     * @returns {object} a [position structure](https://docs.ccxt.com/#/?id=position-structure)
     */
    public override object parsePredictionPosition(object position, object market = null)
    {
        // `position` is a spotClearinghouseState balance entry ({ coin, total, hold, entryNtl })
        // enriched with the current mid price (markPx); hyperliquid does not return the position
        // value / entry price / pnl for outcome tokens, so they are computed here
        object outcomeObj = this.safeOutcome(null, market);
        object totalStr = this.safeString(position, "total");
        object total = this.parseNumber(totalStr);
        object entryNtlStr = this.safeString(position, "entryNtl");
        object entryPrice = null;
        if (isTrue(isTrue(isTrue((!isEqual(entryNtlStr, null))) && isTrue((!isEqual(totalStr, null)))) && !isTrue(Precise.stringEq(totalStr, "0"))))
        {
