        object dedupedValues = new List<object>(((IDictionary<string,object>)deduped).Values);
        object parsed = this.parsePredictionOrders(dedupedValues, null, since);
        object outcomeHandle = null;
        if (isTrue(!isEqual(outcome, null)))
