    }

    public virtual object parseOrderStatus(object status)
    {
        object statuses = new Dictionary<string, object>() {
            { "triggered", "open" },
            { "filled", "closed" },
            { "open", "open" },
            { "canceled", "canceled" },
            { "rejected", "rejected" },
            { "marginCanceled", "canceled" },
        };
        if (isTrue(isEqual(status, null)))
        {
            return null;
        }
        if (isTrue(((string)status).EndsWith(((string)"Rejected"))))
        {
            return "rejected";
        }
        if (isTrue(((string)status).EndsWith(((string)"Canceled"))))
        {
            return "canceled";
        }
        return this.safeString(statuses, status, status);
    }

    public virtual object parseOrderType(object status)
    {
        object statuses = new Dictionary<string, object>() {
            { "stop limit", "limit" },
            { "stop market", "market" },
        };
        object statusLower = ((bool) isTrue(status)) ? ((string)status).ToLower() : null;
        return this.safeString(statuses, statusLower, statusLower);
    }

    public virtual object parseTimeInForce(object timeInForce)
    {
        object statuses = new Dictionary<string, object>() {
            { "gtc", "GTC" },
            { "ioc", "IOC" },
            { "fok", "FOK" },
            { "alo", "PO" },
