    /**
     * @method
     * @name hyperliquid#fetchEvents
     * @description Groups outcome markets by their underlying (e.g. BTC-ABOVE-78213) into event structures. Each event contains both the YES and NO markets.
     * @param {object} [params] extra parameters
     * @param {string} [params.query] a single query string to filter by (matches description/outcome)
     * @param {string[]} [params.queries] multiple query strings (alternative to query)
     * @returns {PredictionEvent[]} array of event structures
     */
    public async override Task<object> fetchEvents(object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        this.requireEventQuery(parameters);
        object queries = this.parseSearchQueries(parameters);
        // hyperliquid has no dedicated events endpoint - events are grouped from the outcome
        // markets. use the cached load so the handles advertised here always match the
        // outcome cache (hyperliquid re-assigns outcome ids over time; a fresh fetch could
        // disagree with a previously warmed cache within the same session)
        object marketsDict = await this.loadMarkets();
        object marketValues = this.toArray(marketsDict);
        // Group markets by parentSymbol
        object groupMap = new Dictionary<string, object>() {};
        object lowerQueries = new List<object>() {};
        for (object i = 0; isLessThan(i, getArrayLength(queries)); postFixIncrement(ref i))
        {
            object queryString = ((string)getValue(queries, i));
            ((IList<object>)lowerQueries).Add(((string)queryString).ToLower());
        }
        object lowerQueriesLength = getArrayLength(lowerQueries);
        for (object i = 0; isLessThan(i, getArrayLength(marketValues)); postFixIncrement(ref i))
        {
            object mkt = getValue(marketValues, i);
            if (!isTrue(this.safeBool(((object)mkt), "prediction", false)))
            {
                continue;
            }
            object info = this.safeDict(((object)mkt), "info", new Dictionary<string, object>() {});
            object parentSymbol = this.safeString(info, "parentSymbol", this.safeString(mkt, "symbol"));
            // Apply query filter
            if (isTrue(isGreaterThan(lowerQueriesLength, 0)))
            {
                object description = ((string)this.safeString(info, "description", "")).ToLower();
                object parentSymbolOrEmpty = ((bool) isTrue((!isEqual(parentSymbol, null)))) ? parentSymbol : "";
                object symLower = ((string)parentSymbolOrEmpty).ToLower();
                // the parentSymbol uses hyphens (BTC-ABOVE-...), so match the haystack word-by-word
                // and require every word of a query to appear, letting "BTC above" match BTC-ABOVE
                object haystack = add(add(description, " "), symLower);
                object matches = false;
                for (object qi = 0; isLessThan(qi, getArrayLength(lowerQueries)); postFixIncrement(ref qi))
                {
                    object words = ((string)getValue(lowerQueries, qi)).Split(new [] {((string)" ")}, StringSplitOptions.None).ToList<object>();
                    object wordsLength = getArrayLength(words);
                    object allWords = true;
                    for (object wi = 0; isLessThan(wi, wordsLength); postFixIncrement(ref wi))
                    {
                        object word = getValue(words, wi);
                        if (isTrue(isTrue((!isEqual(word, ""))) && isTrue((isEqual(getIndexOf(haystack, word), -1)))))
                        {
                            allWords = false;
                            break;
                        }
                    }
                    if (isTrue(allWords))
                    {
                        matches = true;
                        break;
                    }
                }
                if (!isTrue(matches))
                {
                    continue;
                }
            }
            if (!isTrue((inOp(groupMap, parentSymbol))))
            {
                ((IDictionary<string,object>)groupMap)[(string)parentSymbol] = new List<object>() {};
            }
            ((IList<object>)(IList<object>)(getValue(groupMap, parentSymbol))).Add(mkt);
        }
        object events = new List<object>() {};
        object groupKeys = new List<object>(((IDictionary<string,object>)groupMap).Keys);
        for (object gi = 0; isLessThan(gi, getArrayLength(groupKeys)); postFixIncrement(ref gi))
        {
            object key = getValue(groupKeys, gi);
            object groupMarkets = (IList<object>)(getValue(groupMap, key));
            object eventVar = this.parseEvent(new Dictionary<string, object>() {
                { "parentSymbol", key },
                { "markets", groupMarkets },
            });
            ((IList<object>)events).Add(eventVar);
        }
        // applyEventFetchParams caches via setEvents (keyed by id/slug/handle) before filtering,
        // so getEvent() resolves these events by any of the three keys
        return this.applyEventFetchParams(events, parameters, queries);
    }

    /**
     * @ignore
     * @method
     * @name hyperliquid#parseEvent
     * @description parses a grouped set of outcome markets into a unified prediction event object
     * @param {object} raw a dict with parentSymbol and markets entries
     * @returns {object} an event structure
     */
    public virtual object parseEvent(object raw)
