        {
            object titleSuffix = "";
            if (isTrue(targetPrice))
            {
                titleSuffix = add(add(titleSuffix, " ABOVE "), targetPrice);
            }
            if (isTrue(expiryRaw))
            {
                titleSuffix = add(add(titleSuffix, " @ "), expiryRaw);
            }
            title = add(underlying, titleSuffix);
        }
        object endValue = ((bool) isTrue((!isEqual(expiryMs, null)))) ? expiryMs : firstExpiry;
        return this.extend(new Dictionary<string, object>() {
            { "id", parentSymbol },
            { "slug", parentSymbol },
            { "event", parentSymbol },
            { "title", title },
            { "markets", markets },
            { "underlying", underlying },
            { "targetPrice", targetPrice },
            { "class", this.safeString(desc, "class") },
            { "period", this.safeString(desc, "period") },
            { "url", null },
            { "image", null },
            { "created", null },
            { "createdDatetime", null },
            { "end", endValue },
            { "endDatetime", expiryDatetime },
            { "category", "crypto" },
            { "lastUpdatedAt", null },
            { "resolutionSource", "Hyperliquid mark price" },
            { "resolved", null },
            { "info", raw },
        });
    }

